  SVScoped scoped(scope_);
  if (!simutil_get_mem(phys_addr, (svBitVecVal *)minibuf)) {
    std::ostringstream oss;
    oss << "Could not read memory word at physical index 0x" << std::hex
        << phys_addr << ".";
    throw std::runtime_error(oss.str());
  }
}

